<template>
  <view class="page">
    <view class="card">
      <text class="title">{{ notice.title || '隐私政策更新提醒' }}</text>
      <text class="content">{{ notice.content || '我们更新了隐私政策，请先阅读并再次同意后继续使用相关功能。' }}</text>

      <view class="agree-row" @tap="toggleAgree">
        <view class="checkbox" :class="{ checked: agreed }">{{ agreed ? '✓' : '' }}</view>
        <text class="agree-text">我已阅读并同意继续按更新后的隐私政策处理信息</text>
      </view>

      <view class="actions">
        <button class="btn plain" @tap="viewPolicy">查看隐私政策</button>
        <button class="btn" type="primary" @tap="submit">同意并继续</button>
      </view>
    </view>
  </view>
</template>

<script setup>
import { ref } from 'vue'
import { onLoad } from '@dcloudio/uni-app'
import {
  getCachedNotice,
  fetchPrivacyConsentNotice,
  acceptPrivacyConsent
} from '@/utils/privacy-consent.js'

const notice = ref({
  title: '',
  content: '',
  policy_url: '',
  version: 0
})
const agreed = ref(false)
const version = ref(0)

onLoad(async (query) => {
  version.value = Number(query?.v || 0)
  const cached = getCachedNotice()
  if (cached) {
    notice.value = cached
    if (!version.value) version.value = Number(cached.version || 0)
  }
  try {
    const remote = await fetchPrivacyConsentNotice()
    notice.value = remote
    if (!version.value) version.value = Number(remote.version || 0)
  } catch (e) {
    // keep cached content
  }
})

const toggleAgree = () => {
  agreed.value = !agreed.value
}

const viewPolicy = () => {
  const u = String(notice.value.policy_url || '').trim()
  if (!u) {
    uni.showToast({ title: '暂未配置隐私政策链接', icon: 'none' })
    return
  }
  if (/^https?:\/\//.test(u)) {
    uni.navigateTo({
      url: `/uni_modules/uni-id-pages/pages/common/webview/webview?url=${encodeURIComponent(u)}`
    })
    return
  }
  uni.navigateTo({ url: u })
}

const submit = async () => {
  if (!agreed.value) {
    uni.showToast({ title: '请先勾选同意', icon: 'none' })
    return
  }
  if (!version.value) {
    uni.showToast({ title: '隐私版本无效，请稍后重试', icon: 'none' })
    return
  }
  try {
    await acceptPrivacyConsent(version.value)
    uni.showToast({ title: '已同意', icon: 'success' })
    setTimeout(() => {
      uni.navigateBack({ delta: 1 })
    }, 180)
  } catch (e) {
    uni.showToast({ title: e.message || '提交失败', icon: 'none' })
  }
}
</script>

